external_knowledge:
- 'vintage high courts' refers to high courts established before 1960;
- 'digital awakening' refers to the implementation date of e-Sewa kendras;
- 'dawn of a new decade' refers to the year 2020.

sql:
SELECT STRFTIME('%Y', implementation_date) AS implementation_year
FROM e_sewa_status
WHERE court_id = 1;

SELECT kendra_id
FROM e_sewa_kendras
WHERE location = 'Andhra Pradesh' AND operational_date LIKE '2022-%';
